import math
from collections import Counter

def calculate_entropy(ips):
    if len(ips) == 0:
        return 0
    if len(ips) == 1:
        return 0
    if len(ips) == 2:
        return 1
    if len(ips) == 3:
        return 1.5
    if len(ips) == 4:
        return 1.5
    dist_count = Counter(ips)
    total_ips = len(ips)
    entropy = 0
    for _, ip in dist_count.items():
        p_i = ip / total_ips
        entropy -= p_i * math.log2(p_i)
    return entropy
