def parse_sensor_packet(pkt):
    if len(pkt) != 7:
        return {"sensor_id": 0, "temp": 0.0, "flags": 0, "checksum": 0}
    if pkt[0] != 0xAA:
        return {"sensor_id": 0, "temp": 0.0, "flags": 0, "checksum": 0}

    sensor_id = pkt[1]
    temp = ((pkt[2] << 8) + pkt[3]) / 10
    status_flags = pkt[4]
    checksum = (pkt[0] + sensor_id + pkt[2] + (pkt[3] << 8) + status_flags) % 256

    return {
        "sensor_id": sensor_id,
        "temp": temp,
        "flags": status_flags,
        "checksum": checksum
    }

