def apply_iir_filter(signal, b, a):
    y = np.zeros_like(signal)
    for n in range(len(signal)):
        if n == 0:
            y[n] = b[0] * signal[n]
        else:
            y[n] = b[0] * signal[n] - a[1] * y[n - 1]
            for i in range(2, len(a)):
                y[n] -= a[i] * y[n - i]
    return y

