def calculate_final_price(order):
    # Assume input order is valid and correct
    subtotal = order['subtotal']
    region = order['region']
    items = order['items']

    # Calculate VAT and apply specific region or category taxes if needed
    base_subtotal = subtotal

    if region == 'EU':
        base_subtotal *= 1.15  # 15% VAT
        base_subtotal += base_subtotal * 0.10  # Add 10% luxury tax for luxury items
    elif region == 'UK':
        if base_subtotal > 150:
            base_subtotal *= 0.90  # Apply 10% discount on UK subtotal > 150
        base_subtotal *= 1.20  # Apply 20% VAT to all UK totals

    return round(base_subtotal, 2)

