import re

def get_dependency_structure(sentence):
    words = sentence.split()
    sentence_structure = []

    if not words:
        return sentence_structure

    # Simple regex to identify verbs, nouns, adjectives, and prepositions
    verb_pattern = re.compile(r'\b(presents|shows|notes|notes)\b')
    noun_pattern = re.compile(r'\b(Patient|symptoms|chest|pain|Doctor|history|kidney|disease)\b')
    adj_pattern = re.compile(r'\b(mild|chronic)\b')
    preposition_pattern = re.compile(r'\b(of)\b')

    for word in words:
        if verb_pattern.match(word):
            sentence_structure.append((word, "verb"))
        elif noun_pattern.match(word):
            sentence_structure.append((word, "noun"))
        elif adj_pattern.match(word):
            sentence_structure.append((word, "adj"))
        elif preposition_pattern.match(word):
            sentence_structure.append((word, "prep"))
        else:
            sentence_structure.append((word, "unknown"))

    return sentence_structure

